package com.chaobo.scm.supplier.infrastructure.persistence.contract;
import com.chaobo.scm.supplier.application.contract.*;import com.chaobo.scm.supplier.domain.contract.*;import com.chaobo.scm.supplier.domain.quote.*;import com.chaobo.scm.supplier.domain.shared.IdentifierGenerator;import com.chaobo.scm.supplier.infrastructure.persistence.item.SupplierItemPriceSnapshotMapper;import org.springframework.stereotype.Repository;
@Repository public class MyBatisPriceAgreementProjection implements PriceAgreementProjectionPort{private final PriceAgreementProjectionMapper mapper;private final SupplierItemPriceSnapshotMapper snapshots;private final IdentifierGenerator ids;public MyBatisPriceAgreementProjection(PriceAgreementProjectionMapper mapper,SupplierItemPriceSnapshotMapper snapshots,IdentifierGenerator ids){this.mapper=mapper;this.snapshots=snapshots;this.ids=ids;}public void activate(SupplierContractAggregate contract,SupplierQuoteAggregate quote){mapper.upsert(new PriceAgreementProjectionMapper.Header(contract.agreement(),contract.id(),quote.id(),contract.supplierId(),quote.currency(),contract.from(),contract.to(),1,contract.version()));Long agreementId=mapper.agreementId(contract.id());for(var line:quote.lines()){mapper.upsertLine(new PriceAgreementProjectionMapper.Line(agreementId,line.skuCode(),line.unitPrice(),line.taxRate(),line.moq(),line.deliveryDays()));snapshots.upsert(ids.nextId(),contract.supplierId(),line.skuCode(),contract.agreement(),quote.currency(),line.unitPrice(),line.taxRate(),contract.from(),contract.to(),contract.id(),quote.id(),contract.version());}}public void renew(SupplierContractAggregate contract){mapper.renew(contract.id(),contract.to(),contract.version());}public void terminate(SupplierContractAggregate contract){mapper.terminate(contract.id(),contract.version());}}
